-- =============================================================================
-- EduFlow ג€” Meeting Calendar Phase 1 (Architecture Foundation)
-- =============================================================================
-- Independent module for institution meeting scheduling.
-- State changes and slot mutations are allowed only through SECURITY DEFINER RPCs.
-- Direct client writes to meetings.current_state are prohibited.

-- -----------------------------------------------------------------------------
-- Tables
-- -----------------------------------------------------------------------------

CREATE TABLE public.meetings (
    id                  UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    institution_id      UUID        NOT NULL REFERENCES public.institutions (id) ON DELETE RESTRICT,
    creator_id          UUID        NOT NULL REFERENCES public.users (id) ON DELETE RESTRICT,
    requester_id        UUID        NOT NULL REFERENCES public.users (id) ON DELETE RESTRICT,
    calendar_owner_id   UUID        NOT NULL REFERENCES public.users (id) ON DELETE RESTRICT,
    recipient_id        UUID        NOT NULL REFERENCES public.users (id) ON DELETE RESTRICT,
    subject             TEXT        NOT NULL,
    reason              TEXT        NOT NULL,
    duration_minutes    INTEGER     NOT NULL,
    current_state       TEXT        NOT NULL DEFAULT 'REQUESTED',
    selected_slot_id    UUID,
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT meetings_subject_not_blank CHECK (btrim(subject) <> ''),
    CONSTRAINT meetings_reason_not_blank CHECK (btrim(reason) <> ''),
    CONSTRAINT meetings_duration_valid CHECK (duration_minutes IN (15, 30, 45, 60)),
    CONSTRAINT meetings_state_valid CHECK (
        current_state IN (
            'REQUESTED',
            'WAITING_FOR_OWNER_APPROVAL',
            'WAITING_FOR_SLOT_PROPOSAL',
            'WAITING_FOR_SLOT_SELECTION',
            'WAITING_FOR_FINAL_CONFIRMATION',
            'CONFIRMED',
            'RESCHEDULING',
            'CANCELLED',
            'COMPLETED'
        )
    ),
    CONSTRAINT meetings_calendar_owner_is_party CHECK (
        calendar_owner_id IN (requester_id, recipient_id)
    ),
    CONSTRAINT meetings_creator_is_requester CHECK (creator_id = requester_id),
    CONSTRAINT meetings_parties_distinct CHECK (requester_id <> recipient_id)
);

COMMENT ON TABLE public.meetings IS
    'Meeting Calendar meetings (Phase 1). Independent from requests.';

CREATE INDEX idx_meetings_institution_id ON public.meetings (institution_id);
CREATE INDEX idx_meetings_institution_state ON public.meetings (institution_id, current_state);
CREATE INDEX idx_meetings_requester_id ON public.meetings (requester_id);
CREATE INDEX idx_meetings_recipient_id ON public.meetings (recipient_id);
CREATE INDEX idx_meetings_calendar_owner_id ON public.meetings (calendar_owner_id);

CREATE TRIGGER meetings_set_updated_at
    BEFORE UPDATE ON public.meetings
    FOR EACH ROW
    EXECUTE PROCEDURE set_updated_at();

CREATE TABLE public.meeting_participants (
    id                  UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    meeting_id          UUID        NOT NULL REFERENCES public.meetings (id) ON DELETE CASCADE,
    institution_id      UUID        NOT NULL REFERENCES public.institutions (id) ON DELETE RESTRICT,
    user_id             UUID        NOT NULL REFERENCES public.users (id) ON DELETE RESTRICT,
    participant_role    TEXT        NOT NULL,
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT meeting_participants_role_valid CHECK (
        participant_role IN ('creator', 'requester', 'recipient', 'calendar_owner')
    ),
    CONSTRAINT meeting_participants_unique_role_per_meeting
        UNIQUE (meeting_id, participant_role),
    CONSTRAINT meeting_participants_unique_user_role_per_meeting
        UNIQUE (meeting_id, user_id, participant_role)
);

COMMENT ON TABLE public.meeting_participants IS
    'Formal participant roles for a meeting (Phase 1).';

CREATE INDEX idx_meeting_participants_meeting_id ON public.meeting_participants (meeting_id);
CREATE INDEX idx_meeting_participants_institution_id ON public.meeting_participants (institution_id);
CREATE INDEX idx_meeting_participants_user_id ON public.meeting_participants (user_id);

CREATE TABLE public.meeting_slots (
    id                  UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    meeting_id          UUID        NOT NULL REFERENCES public.meetings (id) ON DELETE CASCADE,
    institution_id      UUID        NOT NULL REFERENCES public.institutions (id) ON DELETE RESTRICT,
    starts_at           TIMESTAMPTZ NOT NULL,
    ends_at             TIMESTAMPTZ NOT NULL,
    slot_status         TEXT        NOT NULL DEFAULT 'proposed',
    created_by_user_id  UUID        NOT NULL REFERENCES public.users (id) ON DELETE RESTRICT,
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT meeting_slots_status_valid CHECK (
        slot_status IN ('proposed', 'selected', 'confirmed', 'superseded', 'rejected')
    ),
    CONSTRAINT meeting_slots_range_valid CHECK (ends_at > starts_at),
    CONSTRAINT meeting_slots_unique_window UNIQUE (meeting_id, starts_at, ends_at)
);

COMMENT ON TABLE public.meeting_slots IS
    'Proposed or selected meeting time slots (1ג€“5 active proposals per meeting).';

CREATE INDEX idx_meeting_slots_meeting_id ON public.meeting_slots (meeting_id);
CREATE INDEX idx_meeting_slots_institution_id ON public.meeting_slots (institution_id);
CREATE INDEX idx_meeting_slots_meeting_status ON public.meeting_slots (meeting_id, slot_status);

ALTER TABLE public.meetings
    ADD CONSTRAINT meetings_selected_slot_fk
    FOREIGN KEY (selected_slot_id) REFERENCES public.meeting_slots (id) ON DELETE SET NULL;

CREATE TABLE public.meeting_audit_events (
    id                  UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
    meeting_id          UUID        NOT NULL REFERENCES public.meetings (id) ON DELETE CASCADE,
    institution_id      UUID        NOT NULL REFERENCES public.institutions (id) ON DELETE RESTRICT,
    actor_user_id       UUID        NOT NULL REFERENCES public.users (id) ON DELETE RESTRICT,
    event_type          TEXT        NOT NULL,
    from_state          TEXT,
    to_state            TEXT,
    metadata            JSONB       NOT NULL DEFAULT '{}'::JSONB,
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT meeting_audit_events_type_valid CHECK (
        event_type IN (
            'meeting_created',
            'state_changed',
            'slot_proposed',
            'slot_selected',
            'meeting_confirmed',
            'meeting_cancelled',
            'meeting_rescheduled'
        )
    )
);

COMMENT ON TABLE public.meeting_audit_events IS
    'Append-only Meeting Calendar audit trail (Phase 1).';

CREATE INDEX idx_meeting_audit_events_meeting_id ON public.meeting_audit_events (meeting_id);
CREATE INDEX idx_meeting_audit_events_institution_id ON public.meeting_audit_events (institution_id);

-- -----------------------------------------------------------------------------
-- Denormalization triggers
-- -----------------------------------------------------------------------------

CREATE OR REPLACE FUNCTION public.meeting_participants_set_institution_id()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    v_institution_id UUID;
BEGIN
    SELECT m.institution_id
    INTO v_institution_id
    FROM public.meetings AS m
    WHERE m.id = NEW.meeting_id;

    IF v_institution_id IS NULL THEN
        RAISE EXCEPTION 'Meeting not found.'
            USING ERRCODE = 'P0002';
    END IF;

    NEW.institution_id := v_institution_id;
    RETURN NEW;
END;
$$;

CREATE TRIGGER meeting_participants_set_institution_id
    BEFORE INSERT ON public.meeting_participants
    FOR EACH ROW
    EXECUTE PROCEDURE public.meeting_participants_set_institution_id();

CREATE OR REPLACE FUNCTION public.meeting_slots_set_institution_id()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    v_institution_id UUID;
BEGIN
    SELECT m.institution_id
    INTO v_institution_id
    FROM public.meetings AS m
    WHERE m.id = NEW.meeting_id;

    IF v_institution_id IS NULL THEN
        RAISE EXCEPTION 'Meeting not found.'
            USING ERRCODE = 'P0002';
    END IF;

    NEW.institution_id := v_institution_id;
    RETURN NEW;
END;
$$;

CREATE TRIGGER meeting_slots_set_institution_id
    BEFORE INSERT ON public.meeting_slots
    FOR EACH ROW
    EXECUTE PROCEDURE public.meeting_slots_set_institution_id();

CREATE OR REPLACE FUNCTION public.meeting_audit_events_set_institution_id()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    v_institution_id UUID;
BEGIN
    SELECT m.institution_id
    INTO v_institution_id
    FROM public.meetings AS m
    WHERE m.id = NEW.meeting_id;

    IF v_institution_id IS NULL THEN
        RAISE EXCEPTION 'Meeting not found.'
            USING ERRCODE = 'P0002';
    END IF;

    NEW.institution_id := v_institution_id;
    RETURN NEW;
END;
$$;

CREATE TRIGGER meeting_audit_events_set_institution_id
    BEFORE INSERT ON public.meeting_audit_events
    FOR EACH ROW
    EXECUTE PROCEDURE public.meeting_audit_events_set_institution_id();

-- -----------------------------------------------------------------------------
-- Direct mutation guards
-- -----------------------------------------------------------------------------

CREATE OR REPLACE FUNCTION public.enforce_meetings_command_only_state_updates()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
    IF OLD.current_state IS DISTINCT FROM NEW.current_state
       AND current_setting('meeting_calendar.allow_state_transition', true) IS DISTINCT FROM 'on'
    THEN
        RAISE EXCEPTION 'Direct meeting state updates are prohibited. Use Meeting Calendar commands.'
            USING ERRCODE = '42501';
    END IF;

    IF OLD.selected_slot_id IS DISTINCT FROM NEW.selected_slot_id
       AND current_setting('meeting_calendar.allow_state_transition', true) IS DISTINCT FROM 'on'
    THEN
        RAISE EXCEPTION 'Direct meeting slot selection updates are prohibited. Use Meeting Calendar commands.'
            USING ERRCODE = '42501';
    END IF;

    RETURN NEW;
END;
$$;

CREATE TRIGGER meetings_enforce_command_only_state_updates
    BEFORE UPDATE ON public.meetings
    FOR EACH ROW
    EXECUTE PROCEDURE public.enforce_meetings_command_only_state_updates();

CREATE OR REPLACE FUNCTION public.enforce_meeting_audit_events_append_only()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
    RAISE EXCEPTION 'Meeting audit events are append-only.'
        USING ERRCODE = '42501';
END;
$$;

CREATE TRIGGER meeting_audit_events_no_update
    BEFORE UPDATE ON public.meeting_audit_events
    FOR EACH ROW
    EXECUTE PROCEDURE public.enforce_meeting_audit_events_append_only();

CREATE TRIGGER meeting_audit_events_no_delete
    BEFORE DELETE ON public.meeting_audit_events
    FOR EACH ROW
    EXECUTE PROCEDURE public.enforce_meeting_audit_events_append_only();

-- -----------------------------------------------------------------------------
-- Authorization helpers
-- -----------------------------------------------------------------------------

CREATE OR REPLACE FUNCTION public.meeting_calendar_user_profile(p_user_id UUID)
RETURNS TABLE (
    user_id UUID,
    institution_id UUID,
    primary_role TEXT,
    status TEXT
)
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
    SELECT u.id, u.institution_id, u.primary_role, u.status
    FROM public.users AS u
    WHERE u.id = p_user_id;
$$;

REVOKE ALL ON FUNCTION public.meeting_calendar_user_profile(UUID) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.meeting_calendar_user_profile(UUID) TO authenticated;

CREATE OR REPLACE FUNCTION public.meeting_calendar_actor_can_read_meeting(p_meeting_id UUID)
RETURNS BOOLEAN
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
    SELECT EXISTS (
        SELECT 1
        FROM public.meetings AS m
        WHERE m.id = p_meeting_id
          AND (
            m.creator_id = auth.uid()
            OR m.requester_id = auth.uid()
            OR m.recipient_id = auth.uid()
            OR m.calendar_owner_id = auth.uid()
            OR public.auth_user_is_active_secretary_for_institution(m.institution_id)
            OR public.auth_user_is_active_institution_manager_for_institution(m.institution_id)
          )
    );
$$;

REVOKE ALL ON FUNCTION public.meeting_calendar_actor_can_read_meeting(UUID) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.meeting_calendar_actor_can_read_meeting(UUID) TO authenticated;

CREATE OR REPLACE FUNCTION public.meeting_calendar_validate_role_pair(
    p_requester_role TEXT,
    p_recipient_role TEXT
)
RETURNS BOOLEAN
LANGUAGE plpgsql
IMMUTABLE
AS $$
BEGIN
    IF p_requester_role = 'platform_admin' OR p_recipient_role = 'platform_admin' THEN
        RETURN FALSE;
    END IF;

    IF p_requester_role = 'teacher' AND p_recipient_role IN ('teacher', 'secretary', 'institution_manager') THEN
        RETURN TRUE;
    END IF;

    IF p_requester_role = 'secretary' AND p_recipient_role IN ('teacher', 'institution_manager') THEN
        RETURN TRUE;
    END IF;

    IF p_requester_role = 'institution_manager'
       AND p_recipient_role IN ('teacher', 'secretary', 'institution_manager')
    THEN
        RETURN TRUE;
    END IF;

    RETURN FALSE;
END;
$$;

CREATE OR REPLACE FUNCTION public.meeting_calendar_resolve_calendar_owner_id(
    p_requester_id UUID,
    p_recipient_id UUID,
    p_requester_role TEXT,
    p_recipient_role TEXT
)
RETURNS UUID
LANGUAGE plpgsql
IMMUTABLE
AS $$
BEGIN
    IF p_requester_role = 'teacher'
       AND p_recipient_role IN ('secretary', 'institution_manager')
    THEN
        RETURN p_recipient_id;
    END IF;

    IF p_requester_role = 'secretary' AND p_recipient_role = 'institution_manager' THEN
        RETURN p_recipient_id;
    END IF;

    IF p_requester_role = 'institution_manager' AND p_recipient_role = 'teacher' THEN
        RETURN p_recipient_id;
    END IF;

    IF p_requester_role = 'institution_manager' AND p_recipient_role = 'secretary' THEN
        RETURN p_recipient_id;
    END IF;

    RETURN p_recipient_id;
END;
$$;

CREATE OR REPLACE FUNCTION public.meeting_calendar_initial_state(
    p_requester_id UUID,
    p_calendar_owner_id UUID
)
RETURNS TEXT
LANGUAGE sql
IMMUTABLE
AS $$
    SELECT CASE
        WHEN p_requester_id = p_calendar_owner_id THEN 'WAITING_FOR_SLOT_PROPOSAL'
        ELSE 'WAITING_FOR_OWNER_APPROVAL'
    END;
$$;

CREATE OR REPLACE FUNCTION public.meeting_calendar_write_audit(
    p_meeting_id UUID,
    p_institution_id UUID,
    p_actor_user_id UUID,
    p_event_type TEXT,
    p_from_state TEXT,
    p_to_state TEXT,
    p_metadata JSONB DEFAULT '{}'::JSONB
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
    INSERT INTO public.meeting_audit_events (
        meeting_id,
        institution_id,
        actor_user_id,
        event_type,
        from_state,
        to_state,
        metadata
    ) VALUES (
        p_meeting_id,
        p_institution_id,
        p_actor_user_id,
        p_event_type,
        p_from_state,
        p_to_state,
        COALESCE(p_metadata, '{}'::JSONB)
    );
END;
$$;

REVOKE ALL ON FUNCTION public.meeting_calendar_write_audit(UUID, UUID, UUID, TEXT, TEXT, TEXT, JSONB) FROM PUBLIC;

CREATE OR REPLACE FUNCTION public.meeting_calendar_transition_state(
    p_meeting_id UUID,
    p_expected_from TEXT,
    p_next_state TEXT,
    p_actor_user_id UUID,
    p_event_type TEXT,
    p_metadata JSONB DEFAULT '{}'::JSONB
)
RETURNS public.meetings
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    v_meeting public.meetings%ROWTYPE;
BEGIN
    SELECT *
    INTO v_meeting
    FROM public.meetings
    WHERE id = p_meeting_id
    FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Meeting not found.'
            USING ERRCODE = 'P0002';
    END IF;

    IF v_meeting.current_state IS DISTINCT FROM p_expected_from THEN
        RAISE EXCEPTION 'Invalid meeting state transition from % to %.', v_meeting.current_state, p_next_state
            USING ERRCODE = 'P0001';
    END IF;

    PERFORM set_config('meeting_calendar.allow_state_transition', 'on', true);

    UPDATE public.meetings
    SET current_state = p_next_state
    WHERE id = p_meeting_id
    RETURNING * INTO v_meeting;

    PERFORM public.meeting_calendar_write_audit(
        p_meeting_id,
        v_meeting.institution_id,
        p_actor_user_id,
        p_event_type,
        p_expected_from,
        p_next_state,
        p_metadata
    );

    RETURN v_meeting;
END;
$$;

REVOKE ALL ON FUNCTION public.meeting_calendar_transition_state(UUID, TEXT, TEXT, UUID, TEXT, JSONB) FROM PUBLIC;

-- -----------------------------------------------------------------------------
-- Commands (RPC)
-- -----------------------------------------------------------------------------

CREATE OR REPLACE FUNCTION public.meeting_calendar_create_meeting(
    p_recipient_id UUID,
    p_subject TEXT,
    p_reason TEXT,
    p_duration_minutes INTEGER
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    v_actor public.meeting_calendar_user_profile%ROWTYPE;
    v_recipient public.meeting_calendar_user_profile%ROWTYPE;
    v_meeting_id UUID;
    v_calendar_owner_id UUID;
    v_initial_state TEXT;
BEGIN
    IF auth.uid() IS NULL THEN
        RAISE EXCEPTION 'Permission denied.' USING ERRCODE = '42501';
    END IF;

    SELECT * INTO v_actor FROM public.meeting_calendar_user_profile(auth.uid());
    SELECT * INTO v_recipient FROM public.meeting_calendar_user_profile(p_recipient_id);

    IF v_actor.user_id IS NULL OR v_actor.status <> 'active' THEN
        RAISE EXCEPTION 'Permission denied.' USING ERRCODE = '42501';
    END IF;

    IF v_recipient.user_id IS NULL OR v_recipient.status <> 'active' THEN
        RAISE EXCEPTION 'Recipient is not an active user.' USING ERRCODE = 'P0001';
    END IF;

    IF v_actor.institution_id IS DISTINCT FROM v_recipient.institution_id THEN
        RAISE EXCEPTION 'Cross-institution meetings are not allowed.' USING ERRCODE = 'P0001';
    END IF;

    IF auth.uid() = p_recipient_id THEN
        RAISE EXCEPTION 'Requester and recipient must be different users.' USING ERRCODE = 'P0001';
    END IF;

    IF p_duration_minutes NOT IN (15, 30, 45, 60) THEN
        RAISE EXCEPTION 'Invalid meeting duration.' USING ERRCODE = 'P0001';
    END IF;

    IF btrim(COALESCE(p_subject, '')) = '' OR btrim(COALESCE(p_reason, '')) = '' THEN
        RAISE EXCEPTION 'Subject and reason are required.' USING ERRCODE = 'P0001';
    END IF;

    IF NOT public.meeting_calendar_validate_role_pair(v_actor.primary_role, v_recipient.primary_role) THEN
        RAISE EXCEPTION 'Unauthorized role combination.' USING ERRCODE = '42501';
    END IF;

    v_calendar_owner_id := public.meeting_calendar_resolve_calendar_owner_id(
        auth.uid(),
        p_recipient_id,
        v_actor.primary_role,
        v_recipient.primary_role
    );

    v_initial_state := public.meeting_calendar_initial_state(auth.uid(), v_calendar_owner_id);

    INSERT INTO public.meetings (
        institution_id,
        creator_id,
        requester_id,
        calendar_owner_id,
        recipient_id,
        subject,
        reason,
        duration_minutes,
        current_state
    ) VALUES (
        v_actor.institution_id,
        auth.uid(),
        auth.uid(),
        v_calendar_owner_id,
        p_recipient_id,
        btrim(p_subject),
        btrim(p_reason),
        p_duration_minutes,
        v_initial_state
    )
    RETURNING id INTO v_meeting_id;

    INSERT INTO public.meeting_participants (meeting_id, user_id, participant_role)
    VALUES
        (v_meeting_id, auth.uid(), 'creator'),
        (v_meeting_id, auth.uid(), 'requester'),
        (v_meeting_id, p_recipient_id, 'recipient'),
        (v_meeting_id, v_calendar_owner_id, 'calendar_owner');

    PERFORM public.meeting_calendar_write_audit(
        v_meeting_id,
        v_actor.institution_id,
        auth.uid(),
        'meeting_created',
        NULL,
        v_initial_state,
        jsonb_build_object(
            'requester_id', auth.uid(),
            'recipient_id', p_recipient_id,
            'calendar_owner_id', v_calendar_owner_id,
            'duration_minutes', p_duration_minutes
        )
    );

    RETURN jsonb_build_object('ok', true, 'meeting_id', v_meeting_id, 'current_state', v_initial_state);
END;
$$;

REVOKE ALL ON FUNCTION public.meeting_calendar_create_meeting(UUID, TEXT, TEXT, INTEGER) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.meeting_calendar_create_meeting(UUID, TEXT, TEXT, INTEGER) TO authenticated;

CREATE OR REPLACE FUNCTION public.meeting_calendar_approve_by_owner(p_meeting_id UUID)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    v_meeting public.meetings%ROWTYPE;
BEGIN
    IF auth.uid() IS NULL THEN
        RAISE EXCEPTION 'Permission denied.' USING ERRCODE = '42501';
    END IF;

    SELECT * INTO v_meeting FROM public.meetings WHERE id = p_meeting_id FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Meeting not found.' USING ERRCODE = 'P0002';
    END IF;

    IF v_meeting.calendar_owner_id IS DISTINCT FROM auth.uid() THEN
        RAISE EXCEPTION 'Only the calendar owner may approve this meeting.' USING ERRCODE = '42501';
    END IF;

    PERFORM public.meeting_calendar_transition_state(
        p_meeting_id,
        'WAITING_FOR_OWNER_APPROVAL',
        'WAITING_FOR_SLOT_PROPOSAL',
        auth.uid(),
        'state_changed',
        '{}'::JSONB
    );

    RETURN jsonb_build_object('ok', true, 'current_state', 'WAITING_FOR_SLOT_PROPOSAL');
END;
$$;

REVOKE ALL ON FUNCTION public.meeting_calendar_approve_by_owner(UUID) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.meeting_calendar_approve_by_owner(UUID) TO authenticated;

CREATE OR REPLACE FUNCTION public.meeting_calendar_propose_slots(
    p_meeting_id UUID,
    p_slots JSONB
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    v_meeting public.meetings%ROWTYPE;
    v_slot JSONB;
    v_starts_at TIMESTAMPTZ;
    v_ends_at TIMESTAMPTZ;
    v_slot_count INTEGER;
    v_duration_minutes INTEGER;
    v_actor_role TEXT;
BEGIN
    IF auth.uid() IS NULL THEN
        RAISE EXCEPTION 'Permission denied.' USING ERRCODE = '42501';
    END IF;

    IF p_slots IS NULL OR jsonb_typeof(p_slots) <> 'array' THEN
        RAISE EXCEPTION 'Slots payload must be a JSON array.' USING ERRCODE = 'P0001';
    END IF;

    v_slot_count := jsonb_array_length(p_slots);

    IF v_slot_count < 1 OR v_slot_count > 5 THEN
        RAISE EXCEPTION 'Each meeting must include between 1 and 5 proposed slots.' USING ERRCODE = 'P0001';
    END IF;

    SELECT * INTO v_meeting FROM public.meetings WHERE id = p_meeting_id FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Meeting not found.' USING ERRCODE = 'P0002';
    END IF;

    IF v_meeting.calendar_owner_id IS DISTINCT FROM auth.uid() THEN
        RAISE EXCEPTION 'Only the calendar owner may propose meeting slots.' USING ERRCODE = '42501';
    END IF;

    IF v_meeting.current_state NOT IN ('WAITING_FOR_SLOT_PROPOSAL', 'RESCHEDULING') THEN
        RAISE EXCEPTION 'Slots can only be proposed in WAITING_FOR_SLOT_PROPOSAL or RESCHEDULING.' USING ERRCODE = 'P0001';
    END IF;

    SELECT primary_role
    INTO v_actor_role
    FROM public.users
    WHERE id = auth.uid();

    IF v_actor_role = 'teacher' THEN
        IF EXISTS (
            SELECT 1
            FROM public.users AS u
            WHERE u.id IN (v_meeting.requester_id, v_meeting.recipient_id)
              AND u.id <> auth.uid()
              AND u.primary_role IN ('secretary', 'institution_manager')
        ) THEN
            RAISE EXCEPTION 'Teachers cannot propose meeting times to managers or secretaries.'
                USING ERRCODE = '42501';
        END IF;
    END IF;

    IF v_actor_role = 'secretary' THEN
        IF EXISTS (
            SELECT 1
            FROM public.users AS u
            WHERE u.id IN (v_meeting.requester_id, v_meeting.recipient_id)
              AND u.primary_role = 'institution_manager'
        ) THEN
            RAISE EXCEPTION 'Secretaries cannot propose meeting times to managers.'
                USING ERRCODE = '42501';
        END IF;
    END IF;

    UPDATE public.meeting_slots
    SET slot_status = 'superseded'
    WHERE meeting_id = p_meeting_id
      AND slot_status IN ('proposed', 'selected');

    FOR v_slot IN SELECT value FROM jsonb_array_elements(p_slots)
    LOOP
        v_starts_at := (v_slot ->> 'starts_at')::TIMESTAMPTZ;
        v_ends_at := (v_slot ->> 'ends_at')::TIMESTAMPTZ;

        IF v_starts_at IS NULL OR v_ends_at IS NULL THEN
            RAISE EXCEPTION 'Each slot must include starts_at and ends_at.' USING ERRCODE = 'P0001';
        END IF;

        IF v_ends_at <= v_starts_at THEN
            RAISE EXCEPTION 'Invalid slot date range.' USING ERRCODE = 'P0001';
        END IF;

        IF v_starts_at < NOW() THEN
            RAISE EXCEPTION 'Past slot dates are not allowed.' USING ERRCODE = 'P0001';
        END IF;

        v_duration_minutes := EXTRACT(EPOCH FROM (v_ends_at - v_starts_at))::INTEGER / 60;

        IF v_duration_minutes <> v_meeting.duration_minutes THEN
            RAISE EXCEPTION 'Slot duration must match meeting duration.' USING ERRCODE = 'P0001';
        END IF;

        INSERT INTO public.meeting_slots (
            meeting_id,
            institution_id,
            starts_at,
            ends_at,
            slot_status,
            created_by_user_id
        ) VALUES (
            p_meeting_id,
            v_meeting.institution_id,
            v_starts_at,
            v_ends_at,
            'proposed',
            auth.uid()
        );
    END LOOP;

    PERFORM public.meeting_calendar_transition_state(
        p_meeting_id,
        v_meeting.current_state,
        'WAITING_FOR_SLOT_SELECTION',
        auth.uid(),
        'slot_proposed',
        jsonb_build_object('slot_count', v_slot_count)
    );

    RETURN jsonb_build_object('ok', true, 'current_state', 'WAITING_FOR_SLOT_SELECTION');
END;
$$;

REVOKE ALL ON FUNCTION public.meeting_calendar_propose_slots(UUID, JSONB) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.meeting_calendar_propose_slots(UUID, JSONB) TO authenticated;

CREATE OR REPLACE FUNCTION public.meeting_calendar_select_slot(
    p_meeting_id UUID,
    p_slot_id UUID
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    v_meeting public.meetings%ROWTYPE;
    v_slot public.meeting_slots%ROWTYPE;
BEGIN
    IF auth.uid() IS NULL THEN
        RAISE EXCEPTION 'Permission denied.' USING ERRCODE = '42501';
    END IF;

    SELECT * INTO v_meeting FROM public.meetings WHERE id = p_meeting_id FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Meeting not found.' USING ERRCODE = 'P0002';
    END IF;

    IF v_meeting.current_state <> 'WAITING_FOR_SLOT_SELECTION' THEN
        RAISE EXCEPTION 'Slots can only be selected in WAITING_FOR_SLOT_SELECTION.' USING ERRCODE = 'P0001';
    END IF;

    IF auth.uid() NOT IN (v_meeting.requester_id, v_meeting.recipient_id) THEN
        RAISE EXCEPTION 'Only meeting parties may select a slot.' USING ERRCODE = '42501';
    END IF;

    IF auth.uid() = v_meeting.calendar_owner_id THEN
        RAISE EXCEPTION 'The calendar owner cannot select their own proposed slots.' USING ERRCODE = '42501';
    END IF;

    SELECT * INTO v_slot
    FROM public.meeting_slots
    WHERE id = p_slot_id
      AND meeting_id = p_meeting_id
      AND slot_status = 'proposed';

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Proposed slot not found.' USING ERRCODE = 'P0002';
    END IF;

    UPDATE public.meeting_slots
    SET slot_status = 'rejected'
    WHERE meeting_id = p_meeting_id
      AND id <> p_slot_id
      AND slot_status = 'proposed';

    UPDATE public.meeting_slots
    SET slot_status = 'selected'
    WHERE id = p_slot_id;

    PERFORM set_config('meeting_calendar.allow_state_transition', 'on', true);

    UPDATE public.meetings
    SET selected_slot_id = p_slot_id
    WHERE id = p_meeting_id;

    PERFORM public.meeting_calendar_transition_state(
        p_meeting_id,
        'WAITING_FOR_SLOT_SELECTION',
        'WAITING_FOR_FINAL_CONFIRMATION',
        auth.uid(),
        'slot_selected',
        jsonb_build_object('slot_id', p_slot_id)
    );

    RETURN jsonb_build_object('ok', true, 'current_state', 'WAITING_FOR_FINAL_CONFIRMATION');
END;
$$;

REVOKE ALL ON FUNCTION public.meeting_calendar_select_slot(UUID, UUID) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.meeting_calendar_select_slot(UUID, UUID) TO authenticated;

CREATE OR REPLACE FUNCTION public.meeting_calendar_confirm_meeting(p_meeting_id UUID)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
    v_meeting public.meetings%ROWTYPE;
BEGIN
    IF auth.uid() IS NULL THEN
        RAISE EXCEPTION 'Permission denied.' USING ERRCODE = '42501';
    END IF;

    SELECT * INTO v_meeting FROM public.meetings WHERE id = p_meeting_id FOR UPDATE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Meeting not found.' USING ERRCODE = 'P0002';
    END IF;

    IF v_meeting.current_state <> 'WAITING_FOR_FINAL_CONFIRMATION' THEN
        RAISE EXCEPTION 'Meeting is not awaiting final confirmation.' USING ERRCODE = 'P0001';
    END IF;

    IF auth.uid() <> v_meeting.calendar_owner_id THEN
        RAISE EXCEPTION 'Only the calendar owner may confirm the meeting.' USING ERRCODE = '42501';
    END IF;

    UPDATE public.meeting_slots
    SET slot_status = 'confirmed'
    WHERE id = v_meeting.selected_slot_id;

    PERFORM public.meeting_calendar_transition_state(
        p_meeting_id,
        'WAITING_FOR_FINAL_CONFIRMATION',
        'CONFIRMED',
        auth.uid(),
        'meeting_confirmed',
        jsonb_build_object('slot_id', v_meeting.selected_slot_id)
    );

    RETURN jsonb_build_object('ok', true, 'current_state', 'CONFIRMED');
END;
$$;

